"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[64609],{650:(e,n,i)=>{i.r(n),i.d(n,{data:()=>d});const d={key:"v-2e446ddc",path:"/nodejs/%E5%8C%85%E7%AE%A1%E7%90%86/npm/",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"命令大全",slug:"命令大全",children:[{level:3,title:"1.初始化项目命令",slug:"_1-初始化项目命令",children:[]},{level:3,title:"2.安装模块",slug:"_2-安装模块",children:[]},{level:3,title:"3.更新模块",slug:"_3-更新模块",children:[]},{level:3,title:"4.发布模块",slug:"_4-发布模块",children:[]},{level:3,title:"5.查看模块",slug:"_5-查看模块",children:[]},{level:3,title:"6.卸载模块",slug:"_6-卸载模块",children:[]},{level:3,title:"7.其他",slug:"_7-其他",children:[]}]},{level:2,title:"发布npm包",slug:"发布npm包",children:[{level:3,title:"一、注册NPM账号",slug:"一、注册npm账号",children:[]},{level:3,title:"二、打开命令行，登录 NPM",slug:"二、打开命令行-登录-npm",children:[]},{level:3,title:"三、创建包",slug:"三、创建包",children:[]},{level:3,title:"四、使用刚发布的包",slug:"四、使用刚发布的包",children:[]},{level:3,title:"五、快速发布",slug:"五、快速发布",children:[]}]},{level:2,title:"link",slug:"link",children:[{level:3,title:"git + npm link",slug:"git-npm-link",children:[]}]}],git:{updatedTime:1653451151e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"nodejs/包管理/npm/README.md"}},88575:(e,n,i)=>{i.r(n),i.d(n,{default:()=>S});var d=i(57293);const s=(0,d.uE)('<h2 id="命令大全" tabindex="-1"><a class="header-anchor" href="#命令大全" aria-hidden="true">#</a> 命令大全</h2><h3 id="_1-初始化项目命令" tabindex="-1"><a class="header-anchor" href="#_1-初始化项目命令" aria-hidden="true">#</a> 1.初始化项目命令</h3><table><thead><tr><th>名称</th><th>描述</th><th>实例</th></tr></thead><tbody><tr><td>npm init</td><td>创建一个项目</td><td></td></tr><tr><td>npm init -y</td><td>创建项目,全部选项默认</td><td></td></tr></tbody></table><h3 id="_2-安装模块" tabindex="-1"><a class="header-anchor" href="#_2-安装模块" aria-hidden="true">#</a> 2.安装模块</h3><table><thead><tr><th>名称</th><th>描述</th><th>实例</th></tr></thead><tbody><tr><td>npm install Module Name[@版本号]</td><td>将js库安装在当前执行命令时所在目录下</td><td>npm install express</td></tr><tr><td>npm install Module Name[@版本号] -g</td><td>将js库安装到你的全局目录下</td><td>npm install express -g</td></tr><tr><td>npm install -g Module Name[@版本号]</td><td>将js库安装到你的全局目录下</td><td>npm install -g express</td></tr><tr><td>npm install -gd Module Name[@版本号] --registry=http://registry.npm.taobao.org</td><td>手动指定从哪个镜像服务器获取资源</td><td>npm install -gd express --registry=http://registry.npm.taobao.org</td></tr><tr><td>npm install 或npm i</td><td>安装package.json中全部插件</td><td></td></tr><tr><td>npm install Module Name [--save|-S]</td><td>安装包信息将加入到dependencies（生产阶段的依赖）</td><td>npm install vue -S</td></tr><tr><td>npm install Module Name [--save-dev|-D]</td><td>安装包信息将加入到devDependencies（开发阶段的依赖）,所以开发阶段一般使用它</td><td>npm install eslint -D</td></tr></tbody></table><p>如果安装时出现如下错误</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>npm err! Error:connect ECONNREFUSED 127.0.0.1:8087\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>解决方法:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>npm config set proxy null\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_3-更新模块" tabindex="-1"><a class="header-anchor" href="#_3-更新模块" aria-hidden="true">#</a> 3.更新模块</h3><table><thead><tr><th>名称</th><th>描述</th><th></th></tr></thead><tbody><tr><td>npm update</td><td>可以把当前目录下<code>node_modules</code>子目录里边的对应模块更新至最新版本</td><td></td></tr><tr><td>npm update -g</td><td>可以把全局安装的对应命令行程序更新至最新版。</td><td></td></tr><tr><td></td><td></td><td></td></tr></tbody></table><h3 id="_4-发布模块" tabindex="-1"><a class="header-anchor" href="#_4-发布模块" aria-hidden="true">#</a> 4.发布模块</h3><table><thead><tr><th>名称</th><th>描述</th><th>实例</th></tr></thead><tbody><tr><td>npm unpublish @</td><td>可以撤销发布自己发布过的某个版本代码。</td><td></td></tr><tr><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td></tr></tbody></table><h3 id="_5-查看模块" tabindex="-1"><a class="header-anchor" href="#_5-查看模块" aria-hidden="true">#</a> 5.查看模块</h3><table><thead><tr><th>名称</th><th>描述</th><th>实例</th></tr></thead><tbody><tr><td>npm list =npm ls</td><td>查看本地安装的所有模块</td><td></td></tr><tr><td>npm list Module Name</td><td>查看指定模板</td><td></td></tr><tr><td>npm view Module Name version</td><td>查看模块远程最新版本</td><td>npm view jquery version</td></tr><tr><td>npm view Module Name versions</td><td>查看模块远程所有版本</td><td>npm view jquery versions</td></tr><tr><td></td><td></td><td></td></tr></tbody></table><h3 id="_6-卸载模块" tabindex="-1"><a class="header-anchor" href="#_6-卸载模块" aria-hidden="true">#</a> 6.卸载模块</h3><table><thead><tr><th>名称</th><th>描述</th><th>实例</th></tr></thead><tbody><tr><td>npm uninstall|uni Module Name</td><td>卸载局部模块</td><td></td></tr><tr><td>npm uninstall -g Module Name</td><td>卸载全局模块</td><td></td></tr></tbody></table><h3 id="_7-其他" tabindex="-1"><a class="header-anchor" href="#_7-其他" aria-hidden="true">#</a> 7.其他</h3><table><thead><tr><th>名称</th><th>描述</th><th>实例</th></tr></thead><tbody><tr><td>npm config set registry http://registry.npm.taobao.org</td><td>永久设置镜像服务器</td><td></td></tr><tr><td>npm config set registry https://registry.npmjs.org/</td><td>还原默认镜像地址</td><td></td></tr><tr><td>npm get registry</td><td>获取镜像地址</td><td></td></tr><tr><td>npm root -g</td><td>查看全局安装的位置</td><td></td></tr><tr><td>npm help [name]</td><td>可查看某条命令的详细帮助</td><td><code>npm help install</code></td></tr><tr><td>npm cache clear</td><td>可以清空NPM本地缓存，用于对付使用相同版本号发布新版本代码的人</td><td></td></tr><tr><td>npm install cnpm -g --registry=https://registry.npm.taobao.org</td><td>下载cnpm</td><td>npm init</td></tr><tr><td>npm config set prefix folderpath</td><td>修改全局安装目录</td><td>npm config set prefix &quot;D:\\npm&quot;</td></tr></tbody></table><h2 id="发布npm包" tabindex="-1"><a class="header-anchor" href="#发布npm包" aria-hidden="true">#</a> 发布npm包</h2><p>转自:https://blog.csdn.net/zz00008888/article/details/109024826</p><h3 id="一、注册npm账号" tabindex="-1"><a class="header-anchor" href="#一、注册npm账号" aria-hidden="true">#</a> 一、注册NPM账号</h3><p>https://www.npmjs.com/</p><p>注册好之后记得去填的注册邮箱里面验证一下，在继续下一步，否则发布会报错。</p><h3 id="二、打开命令行-登录-npm" tabindex="-1"><a class="header-anchor" href="#二、打开命令行-登录-npm" aria-hidden="true">#</a> 二、打开命令行，登录 NPM</h3><p>在登录之前，先确定一下 <code>NPM</code> 镜像，如果镜像在之前设置为了淘宝镜像，那么在使用 <code>npm login</code> 登录时会出错，所以需要先将源替换为官方源，然后再上传。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>// 查看当前 npm 源配置\n$ npm config ls\n// 查看当前 npm 全部源配置\n$ npm config ls -l\n// 修改 npm 源地址为官方源\n$ npm config set registry https://registry.npmjs.org/\n// 将 npm 源地址修改为淘宝源（用于安装 npm 速度慢的时候使用）\n$ npm config set registry  https://registry.npm.taobao.org/\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><p>通过执行 <code>$ npm config ls -l</code> 命令查看 <code>metrics-registry = &quot;https://registry.npmjs.org/&quot;</code> 是否为官方源，如果不是则使用上面命令设置为官方源。</p></li><li><p>进行登录</p></li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>// 登录命令\n$ npm login\n\n// 退出登录命令\n$ npm logout\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>运行登录命令之后输入 NPM 账号、密码、邮件</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>dengzemiaodeMacBook-Pro:DZMTest dengzemiao$ npm login\nUsername: dengzemiao\nPassword: \nEmail: (this IS public) xxxxx@163.com\nLogged in as dengzemiao on https://registry.npmjs.org/.\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>登录之后出现最下面这行 Logged in as dengzemiao on https://registry.npmjs.org/. 就说明登录成功了。</p><h3 id="三、创建包" tabindex="-1"><a class="header-anchor" href="#三、创建包" aria-hidden="true">#</a> 三、创建包</h3><p>创建一个文件夹，例如：DZMTest</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ cd DZMTest\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在文件中创建 package.json，运行命令之后一路回车到底，没啥好改的，等下到文件里面也可以改。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ npm init\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>package.json 文件全部字段解释：</p><p>一般创建出来的 package.json 文件只会包含下面其中一部分字段，其他都是隐藏可选字段，根据自己的情况使用，下面列出来大部分常用的字段用于参考：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>{\n  // 发布的包名，默认是上级文件夹名。不得与现在npm中的包名重复。包名不能有大写字母/空格/下滑线!\n  &quot;name&quot;: &quot;#####&quot;,\n  // 版本号，每次要更新\n  &quot;version&quot;: &quot;1.0.0&quot;,\n  // 包的描述\n  &quot;description&quot;: &quot;仅供测试，别下载&quot;,\n  // 文件入口，默认是 index.js，可修改\n  &quot;main&quot;: &quot;index.js&quot;,\n  &quot;scripts&quot;: {\n    // 测试命令，可以不填直接回车\n    &quot;test&quot;: &quot;echo \\&quot;Error: no test specified\\&quot; &amp;&amp; exit 1&quot;\n  },\n  // 作者名称\n  &quot;author&quot;: &quot;###&quot;,\n  // 包遵循的开源协议，默认是ISC\n  &quot;license&quot;: &quot;ISC&quot;,\n  // 因为组件包是公用的，所以 private 为 false\n  &quot;private&quot;: false,\n  // 当前包需要依赖的第三方组件，如何安装使用依赖包，可以看看文章顶部的NPM命令介绍文章\n  &quot;dependencies&quot;: {},\n  // &quot;devDependencies&quot;: {}\n  // 指定代码所在的仓库地址\n  &quot;repository&quot;: {\n    &quot;type&quot;: &quot;git&quot;,\n    &quot;url&quot;: &quot;git+https://github.com/dengzemiao/DZMFullPage.git&quot;\n  },\n  // bug在哪里提\n  &quot;bugs&quot;: {\n     &quot;url&quot;: &quot;https://github.com/dengzemiao/DZMFullPage/issues&quot;\n  },\n  // 项目官网的地址\n  &quot;homepage&quot;: &quot;https://github.com/dengzemiao/DZMFullPage&quot;,\n  // 指定打包后,包中存在的文件夹\n  &quot;files&quot;: [\n    &quot;dist&quot;,\n    &quot;src&quot;\n  ],\n  // 指定了项目的目标浏览器的范围\n  &quot;browserslist&quot;: [\n    &quot;&gt; 1%&quot;,\n    &quot;last 2 versions&quot;,\n    &quot;not ie &lt;= 8&quot;\n  ],\n  // 项目关键词，供搜索\n  &quot;keywords&quot;: [\n    &quot;测试&quot;\n  ]\n}\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>调整 <code>package.json</code>，文件中这两个是必须要填写的，第一个是包名，第二个是版本号，其他随意，更具自己需求调整，没什么特别需求就修改名字跟版本号直接上，其他默认是啥就是啥，看自己需求去改或者增删。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>{\n  &quot;name&quot;: &quot;dzmtest&quot;,\n  &quot;version&quot;: &quot;1.0.0&quot;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><p>去 <code>NPM</code> 官网查询一下当前包名是否存在，存在的话就需要换一个：</p><p><img src="https://img-blog.csdnimg.cn/img_convert/52d40da0da0f71f7e8f04e0a58efe587.png" alt="img"></p></li><li><p>在 <code>DZMTest</code> 文件夹里面在创建一个 <code>index.js</code> 文件，这也是上面设置的入口文件</p><p><code>index.js</code>:</p></li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// index.js 页面方法\nfunction indexTest () {\n  console.log(&#39;index.js 测试输出&#39;)\n}\n// 导出 （module.exports 如果使用不是很熟，百度一下就知道了，用法很简单）\nmodule.exports = { indexTest }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202201110832934.png" alt="img"></p><p>(如果不需要本地测试一下可以跳过) 创建好 index.js 之后可以本地测试一下，创建一个 test.js 在这个文件里面导入 index.js 进行本地使用一下</p><p><code>test.js</code>:</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// 导入 index.js 中的方法进行本地测试\nvar index = require(&#39;./index&#39;)\n// 执行方法\nindex.indexTest()\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202201110832935.png" alt="img"></p><p>我这边用的是 VSCode 装了运行 js 的插件可以直接右键运行代码，输出为</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>[Running] node &quot;/Users/dengzemiao/Desktop/NPM/DZMTest/test.js&quot;\nindex.js 测试输出\n\n[Done] exited with code=0 in 0.054 seconds\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样，说明代码是没有问题的，那么可以进行发布了！！</p><p>(可选) 可以在根目录下新建 .npmignore 文件，设置忽略发布文件，文件不多可以不加，看自己心情。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>.DS_Store\nnode_modules/\nexamples/\npackages/\npublic/\nvue.config.js\nbabel.config.js\n*.map\n*.html\n\n# local env files\n.env.local\n.env.*.local\n\n# Log files\nnpm-debug.log*\nyarn-debug.log*\nyarn-error.log*\n\n# Editor directories and files\n.idea\n.vscode\n*.suo\n*.ntvs*\n*.njsproj\n*.sln\n*.sw*\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202201110832936.png" alt="img"></p><ul><li>发布代码</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ npm publish\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>如果登录的 NPM 账号没有验证邮箱，运行命令之后会报错 you must verify your email before publishing a new package，所以注册之后记得去邮箱里面验证一下，验证之后可以再次运行发布命令，如果还报这个错误可以重新登录一下 NPM 账号:</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>dengzemiaodeMacBook-Pro:DZMTest dengzemiao$ npm publish\nnpm notice \nnpm notice 📦  dzmtest@1.0.0\n......\nnpm ERR! code E403\n// 主要是这行错误\nnpm ERR! 403 403 Forbidden - PUT https://registry.npmjs.org/dzmtest - you must verify your email before publishing a new package: https://www.npmjs.com/email-edit\nnpm ERR! 403 In most cases, you or one of your dependencies are requesting\nnpm ERR! 403 a package version that is forbidden by your security policy.\n\nnpm ERR! A complete log of this run can be found in:\nnpm ERR!     /Users/dengzemiao/.npm/_logs/2020-07-22T03_27_19_859Z-debug.log\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>如果出现这个错误，意思是需要修改 <code>package.json</code> 中的 <code>version</code> 版本号，一般是版本已经存在，新项目发布应该不会报这个错误。</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>dengzemiaodeMacBook-Pro:DZMTest dengzemiao$ npm publish\nnpm notice \nnpm notice 📦  dzmtest@1.0.0\n......\nnpm ERR! code E403\n// 主要是这行错误\nnpm ERR! 403 403 Forbidden - PUT https://registry.npmjs.org/dzmtest - You cannot publish over the previously published versions: 1.0.0.\nnpm ERR! 403 In most cases, you or one of your dependencies are requesting\nnpm ERR! 403 a package version that is forbidden by your security policy.\n\nnpm ERR! A complete log of this run can be found in:\nnpm ERR!     /Users/dengzemiao/.npm/_logs/2020-07-23T03_32_29_970Z-debug.log\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><p><code>You cannot publish over the previously published versions: 1.0.0.</code> 这个错误是版本已经存在，需要修改一个新版本号在上传，这种问题一般在后续版本迭代中出现，忘记修改版本号就直接提交。</p></li><li><p>下面是 <code>version</code> 字段版本格式（这里只是建议这么写，不在意可以随意）</p></li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>1、版本格式：主版本号、次版本号、修订号\n\n2、版本号递增规则如下：（例如：我原本的项目是 1.0.0 版本的话）\n   主版本号：当你做了不兼容的 API 修改，此情况版本应该为 1.0.1\n   次版本号：当你做了向下兼容的功能性新增，此情况版本应该为 1.1.0\n   修订号：当你做了向下兼容的问题修正。此情况版本应该为 2.0.0\n\n3、通过 npm version &lt;update_type&gt; 自动改变版本\n   update_type 为 patch、minor,、major 其中之一，分别表示补丁，小改，大改。\n   例如: $ npm version minor v2.0.0\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>如果有这个错误，可以修改一下 <code>package.json</code> 中的 <code>version</code> 为 <code>1.0.1</code> 版本，然后再次执行发布命令</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>{\n  &quot;name&quot;: &quot;dzmtest&quot;,\n  &quot;version&quot;: &quot;1.0.1&quot;,\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>再次执行发布命令</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>$ npm publish\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>dengzemiaodeMacBook-Pro:DZMTest dengzemiao$ npm publish\nnpm notice \nnpm notice 📦  dzmtest@1.0.0\nnpm notice === Tarball Contents === \nnpm notice 130B index.js    \nnpm notice 114B test.js     \nnpm notice 202B package.json\nnpm notice === Tarball Details === \nnpm notice name:          dzmtest                                 \nnpm notice version:       1.0.0                                   \nnpm notice package size:  471 B                                   \nnpm notice unpacked size: 446 B                                   \nnpm notice shasum:        fc4453748f8b0ca687a2ddea8f650ab75b4c5bec\nnpm notice integrity:     sha512-V+RHefgSXWB/Q[...]Qm/FP3BNcaL9g==\nnpm notice total files:   3                                       \nnpm notice \n+ dzmtest@1.0.0\ndengzemiaodeMacBook-Pro:DZMTest dengzemiao$ \n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>这样就发布成功了！！！</li></ul><h3 id="四、使用刚发布的包" tabindex="-1"><a class="header-anchor" href="#四、使用刚发布的包" aria-hidden="true">#</a> 四、使用刚发布的包</h3>',70),l={id:"_1-创建一个vue项目-并运行起来。",tabindex:"-1"},t=(0,d._)("a",{class:"header-anchor",href:"#_1-创建一个vue项目-并运行起来。","aria-hidden":"true"},"#",-1),a=(0,d.Uk)(" 1."),r={href:"https://juejin.im/post/6877429051242479624",target:"_blank",rel:"noopener noreferrer"},c=(0,d.Uk)("创建一个vue项目"),u=(0,d.Uk)("，并运行起来。"),v=(0,d._)("div",{class:"language-text ext-text line-numbers-mode"},[(0,d._)("pre",{class:"language-text"},[(0,d._)("code",null,"$ vue create npm-test\n")]),(0,d._)("div",{class:"line-numbers","aria-hidden":"true"},[(0,d._)("div",{class:"line-number"})])],-1),m={id:"_2-在新建的-npm-test-项目中导入-dzmtest-包-npm-命令使用介绍以及区别。",tabindex:"-1"},o=(0,d._)("a",{class:"header-anchor",href:"#_2-在新建的-npm-test-项目中导入-dzmtest-包-npm-命令使用介绍以及区别。","aria-hidden":"true"},"#",-1),p=(0,d.Uk)(" 2.在新建的 "),b=(0,d._)("code",null,"npm-test",-1),g=(0,d.Uk)(" 项目中导入 "),h=(0,d._)("code",null,"dzmtest",-1),x=(0,d.Uk)(" 包，"),q={href:"https://juejin.im/post/6877420922538573832",target:"_blank",rel:"noopener noreferrer"},f=(0,d.Uk)("npm 命令使用介绍以及区别"),k=(0,d.Uk)("。"),y=(0,d.uE)('<div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>$ npm i dzmtest\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>dengzemiaodeMacBook-Pro:npm-test dengzemiao$ npm i dzmtest\n+ dzmtest@1.0.0\nadded 1 package and audited 1170 packages in 6.872s\n\n41 packages are looking for funding\n  run `npm fund` for details\n\nfound 0 vulnerabilities\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样就导入成功了！！</p><p>之前在编写 <code>NPM</code> 项目的时候内部文件是这样的：</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202201110832937.png" alt="img"></p><p>导入到其他项目之后文件内部是这样的，在 <code>node_modules</code> 文件目录下：</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202201110832938.png" alt="img"></p><p>这样就很清楚明白该怎么去编写 <code>NPM</code> 项目了，它是直接整个导入进来了之前的 <code>NPM</code> 项目。</p><h4 id="_3-导入成功之后-支持使用" tabindex="-1"><a class="header-anchor" href="#_3-导入成功之后-支持使用" aria-hidden="true">#</a> 3.导入成功之后，支持使用</h4><p>需要在新建的 <code>npm-test</code> 项目里面找到 <code>main.js</code> 全局导入一下 <code>dzmtest</code></p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>import Vue from &#39;vue&#39;\nimport App from &#39;./App.vue&#39;\nimport router from &#39;./router&#39;\nimport store from &#39;./store&#39;\n\n// 如果不是很明白这两种导入方式，可自己百度一下\n// JS是这样导入\nimport DZMTest from &#39;dzmtest&#39;\nVue.prototype.$dzmtest = DZMTest\n\n// 如果是自定义UI组件，就需要这样使用，这样就可以直接支持全局使用\n// import DZMTest from &#39;dzmtest&#39;\n// Vue.use(DZMTest)\n\nVue.config.productionTip = false\n\nnew Vue({\n  router,\n  store,\n  render: h =&gt; h(App)\n}).$mount(&#39;#app&#39;)\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>导入成功之后，可以在任何页面中去使用 <code>$dzmtest</code> 这个属性了，这里是新建的项目，就直接在 <code>Home</code> 页面测试一下就行了</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>&lt;template&gt;\n  &lt;div class=&quot;home&quot;&gt; &lt;/div&gt;\n&lt;/template&gt;\n\n&lt;script&gt;\n\nexport default {\n  mounted () {\n    this.$dzmtest.indexTest()\n  }\n}\n&lt;/script&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202201110832940.png" alt="img"></p><p>然后运行项目就会输出成功了</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>npm run serve\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202201110832941.png" alt="img"></p><p>上传自定义组件到 <code>NPM</code> 到这里就完成了！！！！！！</p><h3 id="五、快速发布" tabindex="-1"><a class="header-anchor" href="#五、快速发布" aria-hidden="true">#</a> 五、快速发布</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>// 修改 npm 源地址为官方源\n$ npm config set registry https://registry.npmjs.org/\n//登录\nnpm login\n//在原来的版本上自动加1,实际上是将package.json文件中的version值修改了\nnpm version patch\n//重新发布包\nnpm publish\n//删除指定的版本\nnpm unpublish 包名@版本号\n//删除整个包,删除需要24之后才能发布相同名字的包\nnpm unpublish 包名 --force\n\n//发布成@panzhiyue/plugin这种形式\nnpm publish --access=public\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="link" tabindex="-1"><a class="header-anchor" href="#link" aria-hidden="true">#</a> link</h2><h3 id="git-npm-link" tabindex="-1"><a class="header-anchor" href="#git-npm-link" aria-hidden="true">#</a> git + npm link</h3>',22),j=(0,d.Uk)("先来看一下"),_={href:"https://link.jianshu.com/?t=https%3A%2F%2Fdocs.npmjs.com%2Fcli%2Finstall",target:"_blank",rel:"noopener noreferrer"},z=(0,d.Uk)("npm install 文档"),M=(0,d.Uk)("。 npm 支持安装 git 仓库，支持 "),E=(0,d._)("code",null,"git",-1),N=(0,d.Uk)(" , "),P=(0,d._)("code",null,"git+ssh",-1),R=(0,d.Uk)(" , "),D=(0,d._)("code",null,"git+http",-1),T=(0,d.Uk)(" , "),$=(0,d._)("code",null,"git+https",-1),U=(0,d.Uk)(" , or "),w=(0,d._)("code",null,"git+file",-1),Z=(0,d.Uk)(" 几种协议，例如："),B=(0,d.uE)('<div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>npm install git+&lt;https://xxx.com/private-package.git&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这样会安装这个仓库的最新版本，如果需要指定版本依赖可以使用 git 的 Tag 来控制。</p><h4 id="使用-tag-控制版本" tabindex="-1"><a class="header-anchor" href="#使用-tag-控制版本" aria-hidden="true">#</a> 使用 Tag 控制版本</h4><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>npm install git+https://xxx.com/private-package.git#v1.0.0\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="npm-link-的使用" tabindex="-1"><a class="header-anchor" href="#npm-link-的使用" aria-hidden="true">#</a> npm link 的使用</h4><p>很多时候我们需要修改 private-package 模块，但又不想每次先提交git，再执行 <code>npm install</code> 命令来看效果，这样效率太低也太麻烦，<code>npm link</code> 可以帮助我们很方便的实现这样的功能。</p><p>两种使用方法：</p><p>第一种、</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code># clone 私有包\ngit clone https://xxx.com/private-package.git\n# 进入私有包目录\ncd private-package\n# 创建全局的link\nnpm link\n\n# 进入项目目录\ncd ../project/abc\n# 将private-package link 到项目\nnpm link private-package\n\n# 取消link \nnpm unlink private-package第二种、直接进入项目目录\ncd ~/project/abc\n# link 相对路径的 private-package\nnpm link ../private-package\n\n# 取消相对路径的 private-package\nnpm unlink ../private-package\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这种方式成本最低，试用于规模比较小的团队，无需搭建私服，只要 git 仓库就可以搞定。</p>',10),F={},S=(0,i(63243).Z)(F,[["render",function(e,n){const i=(0,d.up)("ExternalLinkIcon");return(0,d.wg)(),(0,d.iD)(d.HY,null,[s,(0,d._)("h4",l,[t,a,(0,d._)("a",r,[c,(0,d.Wm)(i)]),u]),v,(0,d._)("h4",m,[o,p,b,g,h,x,(0,d._)("a",q,[f,(0,d.Wm)(i)]),k]),y,(0,d._)("p",null,[j,(0,d._)("a",_,[z,(0,d.Wm)(i)]),M,E,N,P,R,D,T,$,U,w,Z]),B],64)}]])},63243:(e,n)=>{n.Z=(e,n)=>{const i=e.__vccOpts||e;for(const[e,d]of n)i[e]=d;return i}}}]);